import React, { useContext } from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import { AppProvider, AppContext } from './context/AppContext';

import CatalogPage from './pages/CatalogPage';
import LoginPage from './pages/LoginPage';
import ProfilePage from './pages/ProfilePage';
import AdminPage from './pages/AdminPage';

import './styles/global.css';

const Header = () => {
  const { user, setUser } = useContext(AppContext);

  return (
    <nav style={{ 
      background: '#1a1a1a', 
      padding: '1rem 5%', 
      display: 'flex', 
      justifyContent: 'space-between', 
      alignItems: 'center',
      boxShadow: '0 2px 10px rgba(0,0,0,0.3)'
    }}>
      <Link to="/" style={{ color: 'white', fontSize: '1.5rem', fontWeight: 'bold', textDecoration: 'none' }}>
        SNEAKER SHOP
      </Link>
      
      <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
        <Link to="/" style={{ color: 'white', textDecoration: 'none' }}>Каталог</Link>
        
        {user ? (
          <>
            <Link to="/profile" style={{ color: 'white', textDecoration: 'none' }}>Мои заказы</Link>
            
            {/* СИЛОВАЯ ПРОВЕРКА: Пускаем если роль admin ИЛИ если логин "давидд" */}
            {(user.role?.toLowerCase() === 'admin' || user.username === 'давидд') && (
              <Link to="/admin" style={{ 
                color: '#ffcc00', 
                fontWeight: 'bold', 
                textDecoration: 'none',
                border: '1px solid #ffcc00',
                padding: '5px 12px',
                borderRadius: '6px',
                background: 'rgba(255, 204, 0, 0.1)'
              }}>
                Админ-панель
              </Link>
            )}
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <span style={{ color: '#aaa', fontSize: '12px' }}>
                ({user.username} | {user.role})
              </span>
              <button 
                onClick={() => setUser(null)} 
                style={{ background: '#ff4757', color: 'white', border: 'none', padding: '6px 12px', borderRadius: '4px', cursor: 'pointer' }}
              >
                Выйти
              </button>
            </div>
          </>
        ) : (
          <Link to="/login" style={{ background: '#007bff', color: 'white', padding: '8px 16px', borderRadius: '5px', textDecoration: 'none' }}>
            Вход
          </Link>
        )}
      </div>
    </nav>
  );
};

function App() {
  return (
    <AppProvider>
      <BrowserRouter>
        <div className="App">
          <Header />
          <Routes>
            <Route path="/" element={<CatalogPage />} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/profile" element={<ProfilePage />} />
            <Route path="/admin" element={<AdminPage />} />
          </Routes>
        </div>
      </BrowserRouter>
    </AppProvider>
  );
}

export default App;
